
const navItems = [...document.querySelectorAll('.nav-item')];
const views = [...document.querySelectorAll('.view')];
const title = document.getElementById('pageTitle');
const subtitle = document.getElementById('pageSubtitle');
const pageMeta = {
 home:['Good Evening, Ethan ✦','One strategic decision requires your attention today.'],
 stories:['Story Repository','Discover, preserve, and evaluate authentic human stories.'],
 audiences:['Audience Intelligence','Understand where relevance and relationship potential are strongest.'],
 narratives:['Narrative Intelligence','See how public meaning changes over time.'],
 advisory:['AI Advisory Board','Deliberate with distinct strategic perspectives.'],
 campaigns:['Campaign Lab','Turn approved decisions into disciplined execution.'],
 learning:['Institutional Learning','Make every decision improve the next one.'],
 graph:['Knowledge Graph','Explore the relationships across KNIP intelligence.'],
 brief:['Executive Brief','Review the evidence, advisory deliberation, and decision record.']
};
function switchView(name){
 views.forEach(v=>v.classList.toggle('active',v.id===`view-${name}`));
 navItems.forEach(n=>n.classList.toggle('active',n.dataset.view===name));
 title.textContent=pageMeta[name][0]; subtitle.textContent=pageMeta[name][1];
 window.scrollTo({top:0,behavior:'smooth'});
}
navItems.forEach(n=>n.addEventListener('click',()=>switchView(n.dataset.view)));
document.querySelectorAll('[data-view-jump]').forEach(b=>b.addEventListener('click',()=>switchView(b.dataset.viewJump)));
const toast=document.getElementById('toast');
document.querySelectorAll('[data-toast]').forEach(b=>b.addEventListener('click',()=>{
 toast.textContent=b.dataset.toast; toast.classList.add('show'); setTimeout(()=>toast.classList.remove('show'),2200);
}));
document.getElementById('focusToggle').addEventListener('click',e=>{
 document.body.classList.toggle('focus-mode'); e.currentTarget.classList.toggle('active');
 if(document.body.classList.contains('focus-mode')){e.currentTarget.textContent='Exit Focus Mode'}else{e.currentTarget.textContent='◎ Focus Mode'}
});
document.addEventListener('keydown',e=>{
 if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();document.getElementById('globalSearch').focus()}
 if(e.key==='Escape'&&document.body.classList.contains('focus-mode')){document.body.classList.remove('focus-mode');document.getElementById('focusToggle').classList.remove('active');document.getElementById('focusToggle').textContent='◎ Focus Mode'}
});
document.getElementById('globalSearch').addEventListener('keydown',e=>{
 if(e.key==='Enter'){toast.textContent=`Searching KNIP for “${e.target.value}”`;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2200)}
});


document.querySelectorAll('[data-open-brief]').forEach(button=>button.addEventListener('click',()=>switchView('brief')));
document.querySelectorAll('.decision-btn').forEach(button=>button.addEventListener('click',()=>{
 const decision=button.dataset.decision;
 const note=document.getElementById('decisionNote').value.trim();
 const state=document.getElementById('decisionState');
 state.textContent=`Decision recorded: ${decision}`;
 document.getElementById('view-brief').classList.add('decision-complete');
 document.querySelectorAll('.decision-btn').forEach(b=>{b.disabled=true;b.style.opacity='.55'});
 button.disabled=false;button.style.opacity='1';button.textContent=`✓ ${decision}`;
 toast.textContent=note ? `${decision} — rationale stored in institutional memory` : `${decision} — decision record created`;
 toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2800);
}));


