let selectedStoryId=null, storyListMode=false;
const storyGrid=document.getElementById('storyGrid');
function renderStories(){
 if(!storyGrid)return;
 const q=(document.getElementById('storySearch').value||'').toLowerCase();
 const status=document.getElementById('storyStatus').value, theme=document.getElementById('storyTheme').value, sort=document.getElementById('storySort').value;
 let rows=storyIntelligence.filter(s=>(status==='all'||s.status===status)&&(theme==='all'||s.theme===theme)&&[s.title,s.summary,s.location,s.theme,...s.audiences,...s.narratives].join(' ').toLowerCase().includes(q));
 rows.sort((a,b)=>sort==='newest'?b.date.localeCompare(a.date):sort==='evidence'?b.evidence-a.evidence:b.opportunity-a.opportunity);
 storyGrid.innerHTML=rows.map(s=>`<article class="story-card ${selectedStoryId===s.id?'selected':''}" data-story-id="${s.id}"><div><div class="story-card-head"><span class="eyebrow">${s.location} · ${s.theme}</span><em class="story-status ${s.status}">${s.status}</em></div><h3>${s.title}</h3><p>${s.summary}</p><div class="story-meta">${s.audiences.slice(0,2).map(a=>`<span>${a}</span>`).join('')}<span>Reviewer: ${s.reviewer}</span></div></div><div class="story-scores"><div><strong>${s.opportunity}</strong><small>Opportunity</small></div><div><strong>${s.evidence}</strong><small>Evidence</small></div><div><strong>${s.audience}</strong><small>Audience</small></div></div></article>`).join('');
 document.getElementById('storyEmpty').hidden=rows.length>0;
 storyGrid.querySelectorAll('.story-card').forEach(c=>c.addEventListener('click',()=>openStory(Number(c.dataset.storyId))));
}
function openStory(id){selectedStoryId=id;const s=storyIntelligence.find(x=>x.id===id);renderStories();const d=document.getElementById('storyDetail');d.innerHTML=`<div class="detail-top"><div class="detail-topline"><span class="eyebrow">INTELLIGENCE OBJECT #KNIP-${String(s.id).padStart(4,'0')}</span><em class="story-status ${s.status}">${s.status}</em></div><h3>${s.title}</h3><p>${s.summary}</p></div><div class="detail-body"><section class="detail-section"><div class="detail-score-row"><div><strong>${s.opportunity}</strong><small>Opportunity</small></div><div><strong>${s.authenticity}</strong><small>Authenticity</small></div><div><strong>${s.evidence}</strong><small>Evidence</small></div></div></section><section class="detail-section"><h4>Evidence record</h4><div class="evidence-mini">${s.sources.map(x=>`<div><span>${x}</span><b>Verified</b></div>`).join('')}</div></section><section class="detail-section"><h4>Recommended audiences</h4><div class="audience-mini">${s.audiences.map((x,i)=>`<div><span>${i+1}. ${x}</span><b>${Math.max(70,s.audience-i*4)}%</b></div>`).join('')}</div></section><section class="detail-section"><h4>Risk & sensitivity</h4><div class="risk-box">${s.risk}</div></section><section class="detail-section"><h4>Workflow history</h4><div class="timeline-mini">${s.timeline.map(x=>`<div><span>${x}</span><b>✓</b></div>`).join('')}</div></section><section class="detail-section detail-actions"><button class="btn approve" data-view-jump="brief">Open Executive Brief</button><button class="btn warm" data-story-action="advance">Advance Status</button><button class="btn ghost" data-story-action="archive">Archive</button></section><div class="archive-note">All records remain searchable for institutional learning and academic research, including stories not selected for campaigns.</div></div>`;
 d.querySelector('[data-view-jump]').addEventListener('click',()=>switchView('brief'));
 d.querySelectorAll('[data-story-action]').forEach(b=>b.addEventListener('click',()=>{if(b.dataset.storyAction==='archive'){s.status='Archived';toast.textContent='Story preserved in the academic archive';}else{s.status=s.status==='Monitor'?'Review':'Ready';toast.textContent=`Story advanced to ${s.status}`;}toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2200);openStory(s.id);}));
}
['storySearch','storyStatus','storyTheme','storySort'].forEach(id=>{const el=document.getElementById(id);if(el)el.addEventListener(id==='storySearch'?'input':'change',renderStories)});
const viewToggle=document.getElementById('toggleStoryView');if(viewToggle)viewToggle.addEventListener('click',()=>{storyListMode=!storyListMode;storyGrid.classList.toggle('list-mode',storyListMode);viewToggle.textContent=storyListMode?'▦ Grid View':'☷ List View'});
