// Build 0.9 — unified platform architecture demonstration
pageMeta.platform=['Platform Architecture','Inspect KNIP’s entities, evidence, sources, connectors, pipeline, and governance.'];
const platformEntities={
 Mission:{description:'The strategic objective that organizes audience, narrative, resource, execution, and measurement decisions.',fields:['id','objective','owner','time horizon','budget','status','version history']},
 Audience:{description:'A living intelligence profile describing a demographic’s relationship, values, concerns, persuadability, and engagement strategy.',fields:['id','segment definition','health','opportunity','research evidence','playbook','trend']},
 Story:{description:'A preserved intelligence object representing an authentic human story whether or not it is selected for a campaign.',fields:['id','summary','beneficiaries','sources','evidence','risks','status']},
 Narrative:{description:'A strategic meaning structure supported by stories, messengers, evidence, and measurable audience response.',fields:['id','proposition','momentum','audiences','supporting stories','counter-narratives']},
 Messenger:{description:'A credible voice scored by audience trust, expertise, narrative fit, availability, and prior performance.',fields:['id','identity','expertise','trust by audience','conflicts','performance']},
 Campaign:{description:'The execution object connecting an approved decision to channels, resources, timeline, content, and outcomes.',fields:['id','mission','audience','story portfolio','messengers','channels','metrics']},
 Decision:{description:'The permanent record of options considered, evidence used, AI advice, human rationale, and final disposition.',fields:['id','question','options','recommendation','human decision','rationale','audit trail']},
 Evidence:{description:'A validated supporting record with source lineage, reliability, scope, freshness, restrictions, and relevance.',fields:['id','source','collected date','reliability','confidence','scope','validation']},
 Source:{description:'An origin of evidence independently rated for standards, accuracy, transparency, timeliness, and relevance.',fields:['id','publisher','type','reliability profile','license','connector']},
 Organization:{description:'An institution participating in the narrative ecosystem as partner, source, competitor, funder, or subject.',fields:['id','name','role','geography','relationships','history']},
 Outcome:{description:'Observed results linked to a campaign and measured against mission objectives and prior assumptions.',fields:['id','metrics','baseline','result','confidence','attribution']},
 Learning:{description:'A validated lesson derived from decisions and outcomes that modifies future playbooks and recommendations.',fields:['id','finding','evidence','applicability','rule updates','review status']},
 User:{description:'A human actor with role-based permissions, review authority, decision accountability, and audit identity.',fields:['id','role','permissions','organization','decision authority','activity log']}
};
const entityMap=document.getElementById('entityMap'),entityInspector=document.getElementById('entityInspector');
function inspectEntity(name){if(!entityMap||!entityInspector)return;entityMap.querySelectorAll('button').forEach(b=>b.classList.toggle('active',b.dataset.entity===name));const e=platformEntities[name];entityInspector.innerHTML=`<h4>${name}</h4><p>${e.description}</p><div class="entity-fields">${e.fields.map(f=>`<span>${f}</span>`).join('')}</div>`}
if(entityMap){entityMap.innerHTML=Object.keys(platformEntities).map(n=>`<button class="entity-chip" data-entity="${n}">${n}</button>`).join('');entityMap.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>inspectEntity(b.dataset.entity)));inspectEntity('Mission')}
