function renderPlatformPipeline(){const host=document.getElementById('recommendationPipeline');if(!host)return;host.innerHTML=pipelineSteps.map((s,i)=>`<div class="pipeline-step ${i<pipelineStage?'done':i===pipelineStage?'current':''}"><i>${i<pipelineStage?'✓':i+1}</i><span>${s}</span></div>`).join('');document.getElementById('pipelineStatus').textContent=`Stage ${Math.min(pipelineStage+1,10)} of 10`}
const advancePipeline=document.getElementById('advancePipeline');if(advancePipeline)advancePipeline.addEventListener('click',()=>{pipelineStage=Math.min(9,pipelineStage+1);renderPlatformPipeline();toast.textContent=`Pipeline advanced to ${pipelineSteps[pipelineStage]}`;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),1800)});const resetPipeline=document.getElementById('resetPipeline');if(resetPipeline)resetPipeline.addEventListener('click',()=>{pipelineStage=0;renderPlatformPipeline()});renderPlatformPipeline();
