// RC1 — approved executive dashboard API hydration
function setText(id, value) {
  const element = document.getElementById(id);
  if (element && value !== undefined && value !== null) element.textContent = String(value);
}
function setWidth(id, value) {
  const element = document.getElementById(id);
  if (element && Number.isFinite(Number(value))) element.style.width = `${Math.max(0, Math.min(100, Number(value)))}%`;
}
async function hydrateExecutiveDashboard() {
  if (!window.KNIPApi) return;
  const data = await window.KNIPApi.getDashboard();
  const metrics = data.metrics || {};
  const priority = data.priorityDecision || {};
  setText('lastLogin', data.lastLogin);
  setText('metricStories', metrics.storiesValidated?.value);
  setText('metricStoriesTrend', metrics.storiesValidated?.trend);
  setText('metricCampaigns', metrics.campaignsCompleted?.value);
  setText('metricCampaignsTrend', metrics.campaignsCompleted?.trend);
  setText('metricNarratives', metrics.narrativesEmerging?.value);
  setText('metricNarrativesTrend', metrics.narrativesEmerging?.trend);
  setText('metricSentiment', metrics.audienceSentiment?.value);
  setText('metricSentimentTrend', metrics.audienceSentiment?.trend);
  setText('priorityTitle', priority.title);
  setText('prioritySummary', priority.summary);
  setText('audienceMatchValue', priority.audienceMatch !== undefined ? `${priority.audienceMatch}%` : undefined);
  setWidth('audienceMatchBar', priority.audienceMatch);
  setText('evidenceQualityValue', priority.evidenceQuality !== undefined ? `${priority.evidenceQuality}%` : undefined);
  setWidth('evidenceQualityBar', priority.evidenceQuality);
  setText('strategicImpactValue', priority.strategicImpact);
  setWidth('strategicImpactBar', priority.strategicImpactScore);
  setText('decisionReadinessValue', priority.readiness !== undefined ? `${priority.readiness}%` : undefined);
  setText('decisionReadinessState', priority.readinessState);
  setText('approvedImpact', priority.approvedImpact);
  setText('delayImpact', priority.delayImpact);
  document.body.dataset.dashboardSource = data.source || 'KNIP API';
}
hydrateExecutiveDashboard();
